import React from "react";
import ProductSpecs from "../components/product/ProductSpecs";

const API_BASE = "http://localhost:5000";

const RelatedProducts = ({ related, navigate }) => {
  if (!related || related.length === 0) return null;

  return (
    <div className="mt-14">
      <h2 className="text-2xl font-bold text-[#4b2c35] mb-4">
        Sản phẩm liên quan
      </h2>

      <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
        {related.map((p) => (
          <div
            key={p._id}
            onClick={() => navigate(`/product/${p._id}`)}
            className="bg-white rounded-2xl shadow p-3 cursor-pointer hover:-translate-y-1 duration-200"
          >
            <img
              src={API_BASE + p.images[0]}
              className="h-40 w-full object-cover rounded-xl"
              alt=""
            />
            <p className="mt-2 font-semibold text-[#4b2c35]">{p.name}</p>
            <p className="text-pink-600 font-bold">
              {(p.discountPrice || p.price).toLocaleString()}₫
            </p>
          </div>
        ))}
      </div>
    </div>
  );
};

export default RelatedProducts;
